// Extract serial numbers from FOG hosts
// Input: Multiple items, each containing one FOG host object
// Output: {hosts_with_serials: [...]} with serials extracted

console.log(`Processing ${items.length} FOG host items`);

const hostsWithSerials = [];

// Process each item (each contains one FOG host)
for (const item of items) {
  const host = item.json;

  // Extract serial from inventory.sysserial
  const serial = host?.inventory?.sysserial || null;

  hostsWithSerials.push({
    original_host: host,
    serial: serial,
    has_serial: !!serial,
    mac_address: host?.primac || null,
    host_name: host?.name || null,
    host_id: host?.id || null
  });
}

console.log(`Extracted ${hostsWithSerials.length} serial numbers`);

// Return for next step (query cache)
return [{ json: { hosts_with_serials: hostsWithSerials } }];

// Prepare serials for PostgreSQL query
const hostsWithSerials = items[0].json.hosts_with_serials || [];

// Extract only serials that exist (not null)
const serials = [];
for (const host of hostsWithSerials) {
  if (host.serial && host.serial.trim() !== '') {
    serials.push(host.serial);
  }
}

// Format for PostgreSQL IN clause: ('serial1','serial2','serial3')
const serialsForQuery = serials.length > 0 
  ? `('${serials.join("','")}')`
  : "('')"; // Empty query if no serials

// Return data for next steps
return [{
  json: {
    serials_for_query: serialsForQuery,
    serials_list: serials,
    hosts_with_serials: hostsWithSerials,
    total_serials: serials.length
  }
}];

// Get the FOG data (from "Extract serials" node)
const fogItems = items;

// Get the existing serials from PostgreSQL cache
// We need to access the PostgreSQL output differently
// First, let's check what data we have
console.log("Available data structure:");
console.log(JSON.stringify(items, null, 2));

// For now, let's assume the PostgreSQL results are in items[0]
// and the FOG data is in items[1] or similar
// We need to restructure this properly

// Let's get the existing serials from the PostgreSQL output
const existingSerials = [];
if (items[0] && items[0].json && Array.isArray(items[0].json)) {
  // PostgreSQL returns array of {serial: "value"}
  items[0].json.forEach(item => {
    if (item.serial) {
      existingSerials.push(item.serial);
    }
  });
}

// Get the FOG data - it should be in a different item
const fogData = items[1] || items[0]; // Try different positions

// Filter out items that already exist in cache
let newItems = [];
if (fogData && fogData.json && fogData.json.hosts_with_serials) {
  newItems = fogData.json.hosts_with_serials.filter(host => {
    return !existingSerials.includes(host.serial);
  });
}

// Log what we found
console.log(`Existing serials in cache: ${existingSerials.length}`);
console.log(`New items to process: ${newItems.length}`);

// Return only new items
return [{ json: { filtered_hosts: newItems, existing_serials: existingSerials } }];
